'use strict';

/* Keep-alive guards: never crash the server on an unexpected error. */
process.on('uncaughtException', (e) => console.error('[kept running] uncaught:', e && e.message));
process.on('unhandledRejection', (e) => console.error('[kept running] unhandled:', e && (e.message||e)));


/*
 * LSPLASH store server — ZERO dependencies.
 * Uses only Node's built-in modules, so there is NO "npm install" step.
 * Just run:  node server.js   (with your Razorpay keys, see below).
 *
 * Data is stored in a plain file: db.json (created automatically).
 * Payments are verified server-side with your Razorpay key secret,
 * so a browser cannot fake a paid order.
 */

const http = require('http');
const https = require('https');
const crypto = require('crypto');
const fs = require('fs');
const path = require('path');

/* ---------- config (read from the run command) ---------- */
const PORT = process.env.PORT || 3000;
const KEY_ID = process.env.RAZORPAY_KEY_ID;
const KEY_SECRET = process.env.RAZORPAY_KEY_SECRET;
const SESSION_SECRET = process.env.SESSION_SECRET || 'lsplash-dev-secret-change-me';
const GEMINI_API_KEY = process.env.GEMINI_API_KEY || '';
const ANTHROPIC_API_KEY = process.env.ANTHROPIC_API_KEY || '';

if (!KEY_ID || !KEY_SECRET) {
  console.error('\n[STOP] Your Razorpay keys are missing.');
  console.error('Run the server like this (paste YOUR keys):\n');
  console.error('  RAZORPAY_KEY_ID=rzp_test_xxx RAZORPAY_KEY_SECRET=yyy node server.js\n');
  process.exit(1);
}


/* ---------- embedded store page (index.html baked in) ---------- */
const PAGE_B64 = '';
const PAGE_HTML = Buffer.from(PAGE_B64, 'base64').toString('utf8');

/* ---------- tiny JSON "database" ---------- */
const DB_FILE = path.join(__dirname, 'db.json');
let db = { users: [], profiles: {}, orders: [], support: [], nextUserId: 1 };
try { if (fs.existsSync(DB_FILE)) db = JSON.parse(fs.readFileSync(DB_FILE, 'utf8')); } catch (e) {}
if (!Array.isArray(db.support)) db.support = [];
function saveDB() { fs.writeFileSync(DB_FILE, JSON.stringify(db, null, 2)); }

/* ---------- password hashing (built-in scrypt) ---------- */
function hashPassword(pw) {
  const salt = crypto.randomBytes(16).toString('hex');
  const hash = crypto.scryptSync(pw, salt, 64).toString('hex');
  return salt + ':' + hash;
}
function verifyPassword(pw, stored) {
  const [salt, hash] = String(stored).split(':');
  if (!salt || !hash) return false;
  const test = crypto.scryptSync(pw, salt, 64).toString('hex');
  const a = Buffer.from(hash), b = Buffer.from(test);
  return a.length === b.length && crypto.timingSafeEqual(a, b);
}

/* ---------- signed-cookie sessions (stateless) ---------- */
function signSession(userId) {
  const payload = String(userId);
  const sig = crypto.createHmac('sha256', SESSION_SECRET).update(payload).digest('hex');
  return payload + '.' + sig;
}
function readSession(req) {
  const cookie = req.headers.cookie || '';
  const m = cookie.match(/(?:^|;\s*)lsp_sess=([^;]+)/);
  if (!m) return null;
  const val = decodeURIComponent(m[1]);
  const [payload, sig] = val.split('.');
  if (!payload || !sig) return null;
  const expect = crypto.createHmac('sha256', SESSION_SECRET).update(payload).digest('hex');
  const a = Buffer.from(sig), b = Buffer.from(expect);
  if (a.length !== b.length || !crypto.timingSafeEqual(a, b)) return null;
  return parseInt(payload, 10);
}

/* ---------- product catalog (matches the browser exactly) ---------- */
const SERIES = [
  { name: 'LSPTUNE PARTYBOX', prefix: 'PT' }, { name: 'LSPBUGEX', prefix: 'BG' },
  { name: 'LSPHEADFONES', prefix: 'HF' }, { name: 'LSPPFLIP', prefix: 'FL' },
];
const ADJ = ['Ultra','Pro','Max','Elite','Neo','Pulse','Bass','Boom','Wave','Storm','Zen','Core','Air','Edge','Prime','Mini','Plus','Mega','Hyper','Sonic','Vibe','Rush','Beat','Echo','Aura','Blaze','Crisp','Drift','Flux','Glow','Nova','Peak','Rise','Spark','Volt','Apex','Bold','Dash','Fury','Jade','Luxe','Neon','Onyx','Riff','Silk','Tusk'];
const TYPES = ['Speaker','Box','System','Pod','Tower','Dock','Boombox','Station','Hub','Unit','Cube','Orb','Bar','Ring','Disk','Block','Beam','Amp','Node','Base'];
function mulberry32(a){return function(){a|=0;a=(a+0x6D2B79F5)|0;let t=Math.imul(a^(a>>>15),1|a);t=(t+Math.imul(t^(t>>>7),61|t))^t;return((t^(t>>>14))>>>0)/4294967296}}
const CATALOG = (() => {
  const rng = mulberry32(20240513); const byId = new Map(); let id = 1;
  for (const s of SERIES) for (let i = 0; i < 1000; i++) {
    const a = ADJ[~~(rng()*ADJ.length)], t = TYPES[~~(rng()*TYPES.length)], m = ~~(rng()*9000)+1000;
    const price = (~~(rng()*19)+1)*500+499; rng(); rng(); rng();
    byId.set(id, { id, name: `${s.prefix}-${a} ${t} ${m}`, price }); id++;
  }
  return byId;
})();

/* ---------- Razorpay REST calls via built-in https ---------- */
function createRazorpayOrder(amountPaise, receipt, notes) {
  return new Promise((resolve, reject) => {
    const body = JSON.stringify({ amount: amountPaise, currency: 'INR', receipt, notes });
    const auth = Buffer.from(KEY_ID + ':' + KEY_SECRET).toString('base64');
    const req = https.request({
      hostname: 'api.razorpay.com', path: '/v1/orders', method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(body), 'Authorization': 'Basic ' + auth },
    }, (res) => {
      let data = ''; res.on('data', c => data += c);
      res.on('end', () => {
        try {
          const j = JSON.parse(data);
          if (res.statusCode >= 200 && res.statusCode < 300) resolve(j);
          else reject(new Error((j.error && j.error.description) || 'Razorpay error'));
        } catch (e) { reject(new Error('Bad response from Razorpay')); }
      });
    });
    req.on('error', reject); req.write(body); req.end();
  });
}


/* ---------- AI assistant (Gemini) ---------- */
// A few sample products per series so the assistant can recommend real items with real prices.
function catalogSamples() {
  const perSeries = {};
  for (const [id, p] of CATALOG) {
    const s = p.name.split('-')[0];
    (perSeries[s] = perSeries[s] || []).push(p);
  }
  let out = [];
  for (const s of Object.keys(perSeries)) {
    const list = perSeries[s];
    const picks = [list[0], list[Math.floor(list.length/2)], list[list.length-1]];
    out.push(s + ': ' + picks.map(p => p.name + ' (Rs.' + p.price + ')').join(', '));
  }
  return out.join('\n');
}
const STORE_CONTEXT = [
  'You are the shopping assistant for LSPLASH, an online premium speaker store in India.',
  'There are 4 speaker series: LSPTUNE PARTYBOX (party speakers, prefix PT), LSPBUGEX (prefix BG), LSPHEADFONES (headphones, prefix HF), and LSPPFLIP (prefix FL).',
  'The catalog has about 4000 speakers. Prices are in Indian Rupees (Rs.), roughly Rs.999 to Rs.9999.',
  'Payment is via Razorpay (UPI, cards, netbanking, wallets). Orders are placed after payment is verified.',
  'Contact: +91 99995 51979, based in India.',
  'Be friendly, concise, and helpful. Help with general questions AND recommend specific speakers when asked.',
  'When recommending, suggest real product names from the samples below and mention their price. Keep replies short (2-5 sentences).',
  'Here are sample products with prices you can recommend from:',
].join(' ');

function askAI(history) {
  return new Promise((resolve, reject) => {
    const sys = STORE_CONTEXT + '\n' + catalogSamples();
    if (ANTHROPIC_API_KEY) {
      const messages = history.map(m => ({ role: m.role === 'model' ? 'assistant' : 'user', content: String(m.text || '').slice(0, 2000) }));
      const body = JSON.stringify({ model: 'claude-haiku-4-5', max_tokens: 400, system: sys, messages });
      const req = https.request({
        hostname: 'api.anthropic.com', path: '/v1/messages', method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(body), 'x-api-key': ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01' }
      }, (res) => {
        let data = ''; res.on('data', c => data += c);
        res.on('end', () => {
          try {
            const j = JSON.parse(data);
            if (j.error) return reject(new Error(j.error.message || 'AI error'));
            const text = (j.content || []).map(p => p.text).join('') || '';
            resolve(text || 'Sorry, I could not think of a reply.');
          } catch (e) { reject(new Error('Bad response from AI')); }
        });
      });
      req.on('error', reject); req.write(body); req.end();
      return;
    }
    if (GEMINI_API_KEY) {
      const contents = history.map(m => ({ role: m.role === 'model' ? 'model' : 'user', parts: [{ text: String(m.text || '').slice(0, 2000) }] }));
      const body = JSON.stringify({ systemInstruction: { parts: [{ text: sys }] }, contents, generationConfig: { temperature: 0.6, maxOutputTokens: 400 } });
      const req = https.request({
        hostname: 'generativelanguage.googleapis.com', path: '/v1beta/models/gemini-2.5-flash:generateContent', method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(body), 'x-goog-api-key': GEMINI_API_KEY }
      }, (res) => {
        let data = ''; res.on('data', c => data += c);
        res.on('end', () => {
          try {
            const j = JSON.parse(data);
            if (j.error) return reject(new Error(j.error.message || 'AI error'));
            const text = (((j.candidates || [])[0] || {}).content || {}).parts?.map(p => p.text).join('') || '';
            resolve(text || 'Sorry, I could not think of a reply.');
          } catch (e) { reject(new Error('Bad response from AI')); }
        });
      });
      req.on('error', reject); req.write(body); req.end();
      return;
    }
    reject(new Error('AI assistant is not configured yet.'));
  });
}

/* ---------- helpers ---------- */
function send(res, code, obj, headers) {
  const body = JSON.stringify(obj);
  res.writeHead(code, Object.assign({ 'Content-Type': 'application/json' }, headers || {}));
  res.end(body);
}
function publicUser(u) { return { id: u.id, name: u.name, email: u.email, phone: u.phone }; }
function readBody(req) {
  return new Promise((resolve) => {
    let d = ''; req.on('data', c => d += c);
    req.on('end', () => { try { resolve(d ? JSON.parse(d) : {}); } catch (e) { resolve({}); } });
  });
}
function priceCart(items) {
  if (!Array.isArray(items) || !items.length) throw new Error('Cart is empty');
  let total = 0; const lines = [];
  for (const it of items) {
    const p = CATALOG.get(Number(it.id));
    const qty = Math.max(1, Math.min(99, parseInt(it.qty, 10) || 0));
    if (!p) throw new Error('Unknown product in cart');
    total += p.price * qty; lines.push({ name: p.name, qty, price: p.price });
  }
  return { total, lines };
}
function shapeOrder(o) {
  return {
    id: o.id, status: o.status === 'placed' ? 'Confirmed' : 'Pending',
    date: new Date(o.placedAt || o.createdAt).toLocaleDateString('en-IN',
      { day: 'numeric', month: 'short', year: 'numeric', hour: '2-digit', minute: '2-digit' }),
    items: o.items, total: Math.round(o.amount / 100),
  };
}

/* ---------- server ---------- */
const server = http.createServer(async (req, res) => {
  const url = req.url.split('?')[0];
  const userId = readSession(req);

  // API routes
  if (url.startsWith('/api/')) {
    try {
      if (url === '/api/signup' && req.method === 'POST') {
        const { name, email, phone, password } = await readBody(req);
        if (!name || !email || !phone || !password) return send(res, 400, { error: 'All fields are required' });
        if (!/\S+@\S+\.\S+/.test(email)) return send(res, 400, { error: 'Enter a valid email' });
        if (String(password).length < 6) return send(res, 400, { error: 'Password must be at least 6 characters' });
        if (db.users.find(u => u.email === email.toLowerCase())) return send(res, 409, { error: 'Email already registered' });
        const user = { id: db.nextUserId++, name: name.trim(), email: email.toLowerCase(), phone: String(phone).trim(), passHash: hashPassword(String(password)) };
        db.users.push(user); saveDB();
        return send(res, 200, { user: publicUser(user) }, { 'Set-Cookie': `lsp_sess=${encodeURIComponent(signSession(user.id))}; HttpOnly; Path=/; SameSite=Lax; Max-Age=604800` });
      }
      if (url === '/api/login' && req.method === 'POST') {
        const { email, password } = await readBody(req);
        const user = db.users.find(u => u.email === String(email || '').toLowerCase());
        if (!user || !verifyPassword(String(password || ''), user.passHash)) return send(res, 401, { error: 'Invalid email or password' });
        return send(res, 200, { user: publicUser(user) }, { 'Set-Cookie': `lsp_sess=${encodeURIComponent(signSession(user.id))}; HttpOnly; Path=/; SameSite=Lax; Max-Age=604800` });
      }
      if (url === '/api/logout' && req.method === 'POST') {
        return send(res, 200, { ok: true }, { 'Set-Cookie': 'lsp_sess=; HttpOnly; Path=/; Max-Age=0' });
      }
      if (url === '/api/me') {
        const user = userId && db.users.find(u => u.id === userId);
        return send(res, 200, { user: user ? publicUser(user) : null });
      }
      if (url === '/api/profile' && req.method === 'GET') {
        if (!userId) return send(res, 401, { error: 'Please log in' });
        return send(res, 200, { profile: db.profiles[userId] || {} });
      }
      if (url === '/api/profile' && req.method === 'POST') {
        if (!userId) return send(res, 401, { error: 'Please log in' });
        const { name, phone, address, city, pin } = await readBody(req);
        db.profiles[userId] = { name: name || '', phone: phone || '', address: address || '', city: city || '', pin: pin || '' };
        const user = db.users.find(u => u.id === userId);
        if (name && name.trim() && user) user.name = name.trim();
        saveDB();
        return send(res, 200, { profile: db.profiles[userId], user: user ? publicUser(user) : null });
      }
      if (url === '/api/create-order' && req.method === 'POST') {
        if (!userId) return send(res, 401, { error: 'Please log in' });
        const { items, delivery } = await readBody(req);
        const { total, lines } = priceCart(items);
        const amountPaise = total * 100;
        const rzp = await createRazorpayOrder(amountPaise, 'lsp_' + Date.now().toString(36), { userId: String(userId) });
        const localId = 'LSP' + Date.now().toString(36).toUpperCase();
        db.orders.push({ id: localId, userId, razorpayOrderId: rzp.id, amount: amountPaise, status: 'created', items: lines, delivery: delivery || {}, createdAt: new Date().toISOString(), placedAt: null, razorpayPaymentId: null });
        saveDB();
        return send(res, 200, { keyId: KEY_ID, razorpayOrderId: rzp.id, amount: amountPaise, currency: 'INR', localOrderId: localId });
      }
      if (url === '/api/verify-payment' && req.method === 'POST') {
        if (!userId) return send(res, 401, { error: 'Please log in' });
        const { razorpay_order_id, razorpay_payment_id, razorpay_signature } = await readBody(req);
        if (!razorpay_order_id || !razorpay_payment_id || !razorpay_signature) return send(res, 400, { error: 'Missing payment fields' });
        const order = db.orders.find(o => o.razorpayOrderId === razorpay_order_id && o.userId === userId);
        if (!order) return send(res, 404, { error: 'Order not found' });
        const expected = crypto.createHmac('sha256', KEY_SECRET).update(razorpay_order_id + '|' + razorpay_payment_id).digest('hex');
        const a = Buffer.from(expected), b = Buffer.from(String(razorpay_signature));
        if (a.length !== b.length || !crypto.timingSafeEqual(a, b)) return send(res, 400, { error: 'Invalid payment signature' });
        if (order.status !== 'placed') { order.status = 'placed'; order.razorpayPaymentId = razorpay_payment_id; order.placedAt = new Date().toISOString(); saveDB(); }
        return send(res, 200, { order: shapeOrder(order) });
      }
      if (url === '/api/my-orders') {
        if (!userId) return send(res, 401, { error: 'Please log in' });
        const mine = db.orders.filter(o => o.userId === userId && o.status === 'placed').sort((x, y) => (y.placedAt || '').localeCompare(x.placedAt || ''));
        return send(res, 200, { orders: mine.map(shapeOrder) });
      }
      if (url === '/api/support' && req.method === 'POST') {
        const { name, email, subject, message } = await readBody(req);
        if (!name || !email || !message) return send(res, 400, { error: 'Please fill name, email and message' });
        if (!/\S+@\S+\.\S+/.test(email)) return send(res, 400, { error: 'Enter a valid email' });
        const ticket = { id: 'MSG' + Date.now().toString(36).toUpperCase(), userId: userId || null, name: String(name).slice(0,120), email: String(email).slice(0,160), subject: String(subject||'').slice(0,160), message: String(message).slice(0,3000), at: new Date().toISOString() };
        db.support.push(ticket); saveDB();
        return send(res, 200, { ok: true, id: ticket.id });
      }
      // Simple admin view of messages: /api/support-list?key=YOUR_SESSION_SECRET
      if (url.startsWith('/api/support-list')) {
        const q = new URLSearchParams(req.url.split('?')[1] || '');
        if (q.get('key') !== SESSION_SECRET) return send(res, 403, { error: 'Forbidden' });
        return send(res, 200, { messages: db.support.slice().reverse() });
      }
      if (url === '/api/chat' && req.method === 'POST') {
        const { messages } = await readBody(req);
        if (!Array.isArray(messages) || !messages.length) return send(res, 400, { error: 'No messages' });
        const trimmed = messages.slice(-12); // keep last few turns
        try {
          const reply = await askAI(trimmed);
          return send(res, 200, { reply });
        } catch (e) {
          return send(res, 200, { reply: "Sorry, I'm having trouble right now. Please try again in a moment." });
        }
      }
      return send(res, 404, { error: 'Not found' });
    } catch (e) {
      return send(res, 400, { error: e.message || 'Request failed' });
    }
  }

  // Everything else -> the embedded store page
  res.writeHead(200, { 'Content-Type': 'text/html' });
  res.end(PAGE_HTML);
});

server.listen(PORT, '0.0.0.0', () => {
  console.log(`\nLSPLASH store running.  Open  http://localhost:${PORT}\n(Press Control-C to stop.)\n`);
});
